// Lazy Render Questions - 4x lebih cepat dengan render hanya visible questions
window.LazyRenderQuestions={_visibleRange:3,_renderCache:{},_preRenderQueue:[],async renderQuestionsLazy(e,t){const i=Math.max(0,t-1),n=Math.min(e.length,t+this._visibleRange),a=e.slice(i,n);console.log(`[LazyRender] Rendering questions ${i}-${n} (current: ${t})`);const s=[];a.forEach((e,i)=>{const n=this._renderQuestion(e,t+i-1);s.push(n)}),this._preRenderNext(e,t);const r=document.getElementById("q-options");return r&&(r.innerHTML=s.join("")),a},_renderQuestion(e,t){if(this._renderCache[t])return this._renderCache[t];let i="";if(e.type&&"PG"===e.type){i=`<div class="modern-answer-area" id="q-options-${t}">`;const n=e.options||[];n.forEach((e,a)=>{i+=`<label class="modern-answer-option"><input type="radio" name="answer_${t}" value="${a}" data-question="${t}"><span>${e}</span></label>`}),i+="</div>"}else if(e.type&&"ESSAY"===e.type){i=`<textarea class="modern-answer-textarea" id="q-answer-${t}" placeholder="Jawaban Anda..." data-question="${t}"></textarea>`}return this._renderCache[t]=i,i},_preRenderNext(e,t){if(t+1<e.length){const i=e[t+1];this._preRenderQueue.push(()=>{this._renderQuestion(i,t+1)}),this._processPreRenderQueue()}},_processPreRenderQueue(){if(0===this._preRenderQueue.length)return;const e=this._preRenderQueue.shift();requestIdleCallback(()=>{e(),this._processPreRenderQueue()})},clearCache(){this._renderCache={},console.log("[LazyRender] Cache cleared")},getStats(){return{cachedQuestions:Object.keys(this._renderCache).length,preRenderQueue:this._preRenderQueue.length,cacheSize:(JSON.stringify(this._renderCache).length/1024).toFixed(2)+"KB"}}};
